'use client'
import { cn, Presence, useSignal, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import { useRef, type HTMLAttributes, type ReactNode } from 'react'
import styles from './notification.module.css'

export type NotificationVariant = 'info' | 'success' | 'warning' | 'error'

export interface NotificationProps extends Omit<HTMLAttributes<HTMLDivElement>, 'title'> {
  title: ReactNode
  description?: ReactNode
  variant?: NotificationVariant
  dismissible?: boolean
  onDismiss?: () => void
  actions?: ReactNode
  icon?: ReactNode
  labels?: {
    dismiss?: string
  }
}

const assertiveVariants = new Set<NotificationVariant>(['warning', 'error'])

// must outlast --cascivo-motion-exit (150ms)
const EXIT_DURATION = 160

function VariantIcon({ variant }: { variant: NotificationVariant }) {
  if (variant === 'success') {
    return (
      <svg viewBox="0 0 20 20" width="20" height="20" fill="none" aria-hidden="true">
        <circle cx="10" cy="10" r="8" stroke="currentColor" strokeWidth="1.5" />
        <path
          d="M6.5 10.5l2.5 2.5 4.5-5"
          stroke="currentColor"
          strokeWidth="1.5"
          strokeLinecap="round"
          strokeLinejoin="round"
        />
      </svg>
    )
  }
  if (variant === 'warning') {
    return (
      <svg viewBox="0 0 20 20" width="20" height="20" fill="none" aria-hidden="true">
        <path
          d="M10 2.5L18.5 17H1.5L10 2.5z"
          stroke="currentColor"
          strokeWidth="1.5"
          strokeLinejoin="round"
        />
        <path
          d="M10 8v3.5M10 14h.01"
          stroke="currentColor"
          strokeWidth="1.5"
          strokeLinecap="round"
        />
      </svg>
    )
  }
  if (variant === 'error') {
    return (
      <svg viewBox="0 0 20 20" width="20" height="20" fill="none" aria-hidden="true">
        <circle cx="10" cy="10" r="8" stroke="currentColor" strokeWidth="1.5" />
        <path
          d="M10 6v4.5M10 13.5h.01"
          stroke="currentColor"
          strokeWidth="1.5"
          strokeLinecap="round"
        />
      </svg>
    )
  }
  return (
    <svg viewBox="0 0 20 20" width="20" height="20" fill="none" aria-hidden="true">
      <circle cx="10" cy="10" r="8" stroke="currentColor" strokeWidth="1.5" />
      <path d="M10 9v5M10 6.5h.01" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
    </svg>
  )
}

export function Notification({
  title,
  description,
  variant = 'info',
  dismissible = false,
  onDismiss,
  actions,
  icon,
  labels,
  className,
  ...props
}: NotificationProps) {
  useSignals()
  const open = useSignal(true)
  const onDismissRef = useRef(onDismiss)
  onDismissRef.current = onDismiss

  const showDismiss = dismissible || onDismiss !== undefined

  const dismiss = () => {
    open.value = false
    // Call after the exit transition so the parent's removal does not cut it short.
    setTimeout(() => onDismissRef.current?.(), EXIT_DURATION)
  }

  return (
    <Presence present={open}>
      <div
        role={assertiveVariants.has(variant) ? 'alert' : 'status'}
        data-variant={variant}
        className={cn(styles['notification'], className as string | undefined)}
        {...props}
      >
        <span className={styles['icon']} aria-hidden="true">
          {icon ?? <VariantIcon variant={variant} />}
        </span>
        <div className={styles['body']}>
          <div className={styles['title']}>{title}</div>
          {description && <div className={styles['description']}>{description}</div>}
          {actions && <div className={styles['actions']}>{actions}</div>}
        </div>
        {showDismiss && (
          <button
            type="button"
            className={styles['dismiss']}
            aria-label={labels?.dismiss ?? t(builtin.notification.dismiss)}
            onClick={dismiss}
          >
            ✕
          </button>
        )}
      </div>
    </Presence>
  )
}

@layer cascivo.component {
  .notification {
    display: flex;
    gap: var(--cascivo-space-3);
    padding: var(--cascivo-space-4);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-surface);
    background-color: var(--cascivo-color-surface);
    font-family: var(--cascivo-font-sans);
    color: var(--cascivo-color-text);
    opacity: 1;
    transition: opacity var(--cascivo-motion-enter);

    /* Enter: fade in from the styles the browser applies on first render */
    @starting-style {
      opacity: 0;
    }

    /* Exit: Presence sets data-state="closed" before unmounting */
    &[data-state='closed'] {
      opacity: 0;
      transition: opacity var(--cascivo-motion-exit);
    }

    &[data-variant='info'] {
      border-color: color-mix(in oklch, var(--cascivo-color-info) 35%, var(--cascivo-color-border));
      background: color-mix(in oklch, var(--cascivo-color-info) 5%, var(--cascivo-color-bg));
    }

    &[data-variant='success'] {
      border-color: color-mix(
        in oklch,
        var(--cascivo-color-success) 35%,
        var(--cascivo-color-border)
      );
      background: color-mix(in oklch, var(--cascivo-color-success) 5%, var(--cascivo-color-bg));
    }

    &[data-variant='warning'] {
      border-color: color-mix(
        in oklch,
        var(--cascivo-color-warning) 35%,
        var(--cascivo-color-border)
      );
      background: color-mix(in oklch, var(--cascivo-color-warning) 5%, var(--cascivo-color-bg));
    }

    &[data-variant='error'] {
      border-color: color-mix(
        in oklch,
        var(--cascivo-color-destructive) 35%,
        var(--cascivo-color-border)
      );
      background: color-mix(in oklch, var(--cascivo-color-destructive) 5%, var(--cascivo-color-bg));
    }
  }

  .icon {
    display: flex;
    flex-shrink: 0;
    align-items: center;
    line-height: 1;
    margin-block-start: 0.125rem;

    .notification[data-variant='info'] & {
      color: var(--cascivo-color-info);
    }
    .notification[data-variant='success'] & {
      color: var(--cascivo-color-success);
    }
    .notification[data-variant='warning'] & {
      color: var(--cascivo-color-warning);
    }
    .notification[data-variant='error'] & {
      color: var(--cascivo-color-destructive);
    }
  }

  .body {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
    flex: 1;
    min-inline-size: 0;
  }

  .title {
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-semibold);
    line-height: var(--cascivo-leading-snug);
  }

  .description {
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
    line-height: var(--cascivo-leading-normal);
  }

  .actions {
    display: flex;
    flex-wrap: wrap;
    gap: var(--cascivo-space-2);
    margin-block-start: var(--cascivo-space-2);
  }

  .dismiss {
    display: flex;
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    inline-size: 1.5rem;
    block-size: 1.5rem;
    padding: 0;
    font-size: var(--cascivo-text-xs);
    color: var(--cascivo-color-text-muted);
    background: transparent;
    border: none;
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    transition:
      color var(--cascivo-duration-150) var(--cascivo-ease-out),
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      color: var(--cascivo-color-text);
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }
  }
}

@media (forced-colors: active) {
  .notification {
    border: 1px solid CanvasText;
  }

  .notification[data-variant='info'],
  .notification[data-variant='success'],
  .notification[data-variant='warning'],
  .notification[data-variant='error'] {
    border-width: 2px;
  }

  .dismiss:focus-visible {
    outline: 2px solid Highlight;
    outline-offset: 2px;
  }
}

@media (prefers-contrast: more) {
  .notification {
    border-width: 2px;
  }
}
